{"content":"import { useState, useEffect, useRef } from "react";
import content from "@/content/menu-content.json";

// ─── CONTENT ────────────────────────────────────────────────────────────────

const SITE = content.site;
const PLANS = content.plans;
const STEPS = content.steps;
const FAQS = content.faqs;
const CHEF = content.chef;
const EXTRAS = content.extras;
const CATALOG = content.catalog;

// Current week rotation — in production these come from Supabase
const CURRENT_WEEK = {
  label: "Semana del 13 al 18 mayo",
  options: [
    CATALOG.find((p) => p.id === "bolognese")!,
    CATALOG.find((p) => p.id === "pollo-pepitoria")!,
    CATALOG.find((p) => p.id === "lentejas")!,
  ],
  extra: EXTRAS.find((e) => e.id === "crema-zapallo")!,
};

// ─── UTILS ───────────────────────────────────────────────────────────────────

const fmt = (n: number) => n.toLocaleString("es-PY");

// ─── COMPONENTS ──────────────────────────────────────────────────────────────

function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <nav
      style={{
        position: "fixed", top: 0, left: 0, right: 0, zIndex: 50,
        transition: "all 0.3s ease",
        backgroundColor: scrolled ? "#faf7f2" : "transparent",
        boxShadow: scrolled ? "0 2px 16px rgba(0,0,0,0.08)" : "none",
      }}
    >
      <div
        style={{
          maxWidth: 1100, margin: "0 auto", padding: "0 24px",
          display: "flex", alignItems: "center", justifyContent: "space-between",
          height: scrolled ? 64 : 80, transition: "height 0.3s ease",
        }}
      >
        {/* Logo */}
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div
            style={{
              width: 36, height: 36, borderRadius: 10,
              backgroundColor: "#2d5a3d",
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: 18,
            }}
          >
            🍲
          </div>
          <span
            style={{
              fontFamily: "var(--font-playfair)", fontSize: 22,
              fontWeight: 700, color: "#2d5a3d", letterSpacing: "-0.5px",
            }}
          >
            {SITE.name}
          </span>
          <span
            style={{
              fontFamily: "var(--font-lato)", fontSize: 12, color: "#6b6b6b",
              borderLeft: "1px solid #e8e4dc", paddingLeft: 10, marginLeft: 4,
            }}
          >
            {SITE.tagline}
          </span>
        </div>

        {/* Desktop nav */}
        <div style={{ display: "flex", alignItems: "center", gap: 32 }} className="hide-mobile">
          {["Cómo funciona", "Menú", "Planes", "Chef", "FAQ"].map((item) => (
            <a
              key={item}
              href={`#${item.toLowerCase().replace(/ /g, "-")}`}
              style={{
                fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 400,
                color: "#2a2a2a", textDecoration: "none", letterSpacing: "0.3px",
              }}
            >
              {item}
            </a>
          ))}
          <a
            href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20saber%20más%20sobre%20Prep.`}
            style={{
              backgroundColor: "#2d5a3d", color: "#faf7f2",
              padding: "10px 22px", borderRadius: 8,
              fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 700,
              textDecoration: "none", letterSpacing: "0.3px",
              transition: "background-color 0.2s",
            }}
            onMouseEnter={(e) => ((e.target as HTMLElement).style.backgroundColor = "#3d7a52")}
            onMouseLeave={(e) => ((e.target as HTMLElement).style.backgroundColor = "#2d5a3d")}
          >
            Escribir por WhatsApp
          </a>
        </div>

        <button
          className="show-mobile"
          onClick={() => setOpen(!open)}
          style={{
            background: "none", border: "none", cursor: "pointer",
            padding: 8, fontSize: 24,
          }}
        >
          {open ? "✕" : "☰"}
        </button>
      </div>

      {open && (
        <div style={{ backgroundColor: "#faf7f2", borderTop: "1px solid #e8e4dc", padding: "16px 24px 24px" }} className="show-mobile">
          {["Cómo funciona", "Menú", "Planes", "Chef", "FAQ"].map((item) => (
            <a
              key={item}
              href={`#${item.toLowerCase().replace(/ /g, "-")}`}
              onClick={() => setOpen(false)}
              style={{
                display: "block", padding: "12px 0",
                fontFamily: "var(--font-lato)", fontSize: 16, color: "#2a2a2a",
                textDecoration: "none", borderBottom: "1px solid #e8e4dc",
              }}
            >
              {item}
            </a>
          ))}
          <a
            href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20saber%20más%20sobre%20Prep.`}
            style={{
              display: "block", marginTop: 16, backgroundColor: "#2d5a3d",
              color: "#faf7f2", padding: "12px 22px", borderRadius: 8,
              fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 700,
              textDecoration: "none", textAlign: "center",
            }}
          >
            Escribir por WhatsApp
          </a>
        </div>
      )}

      <style>{`
        @media (min-width: 768px) { .show-mobile { display: none !important; } }
        @media (max-width: 767px) { .hide-mobile { display: none !important; } }
      `}</style>
    </nav>
  );
}

