function ComoFunciona() {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => e.isIntersecting && setVisible(true), { threshold: 0.2 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  return (
    <section id="como-funciona" ref={ref} style={{ padding: "100px 24px", backgroundColor: "#fff" }}>
      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
        <div style={{ textAlign: "center", marginBottom: 64 }}>
          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#c4703b", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
            Simple y claro
          </div>
          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#2a2a2a", lineHeight: 1.15 }}>
            Así funciona
          </h2>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 32 }} className="steps-grid">
          {STEPS.map((step, i) => (
            <div
              key={step.number}
              style={{
                opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(24px)",
                transition: `all 0.5s ease ${i * 0.12}s`,
              }}
            >
              <div style={{ fontFamily: "var(--font-playfair)", fontSize: 52, fontWeight: 700, color: "#e8f0e9", lineHeight: 1, marginBottom: 16 }}>
                {step.number}
              </div>
              <h3 style={{ fontFamily: "var(--font-playfair)", fontSize: 20, fontWeight: 700, color: "#2a2a2a", marginBottom: 10 }}>
                {step.title}
              </h3>
              <p style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "#6b6b6b", lineHeight: 1.65 }}>
                {step.description}
              </p>
            </div>
          ))}
        </div>

        <style>{`
          @media (max-width: 900px) { .steps-grid { grid-template-columns: 1fr 1fr !important; } }
          @media (max-width: 600px) { .steps-grid { grid-template-columns: 1fr !important; } }
        `}</style>
      </div>
    </section>
  );
}

function MenuSection() {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => e.isIntersecting && setVisible(true), { threshold: 0.1 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  const stabilityLabel = (n: number) => "🧊".repeat(n);

  return (
    <section id="menu" ref={ref} style={{ padding: "100px 24px", backgroundColor: "#faf7f2" }}>
      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
        <div style={{ textAlign: "center", marginBottom: 64 }}>
          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#c4703b", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
            Esta semana
          </div>
          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#2a2a2a", lineHeight: 1.15, marginBottom: 8 }}>
            {CURRENT_WEEK.label}
          </h2>
          <p style={{ fontFamily: "var(--font-lato)", fontSize: 15, color: "#6b6b6b" }}>
            Pedidos hasta el {SITE.order_cutoff} · Entrega {SITE.delivery_days}
          </p>
        </div>

        {/* Options A/B/C */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 24, marginBottom: 32 }} className="menu-grid">
          {CURRENT_WEEK.options.map((plate, i) => {
            const label = ["A", "B", "C"][i];
            const colors = ["#e8f0e9", "#fde8c8", "#d4edda"];
            const tagColors = ["#2d5a3d", "#c4703b", "#5a8a5a"];
            return (
              <div
                key={plate.id}
                style={{
                  backgroundColor: "#fff", borderRadius: 20,
                  border: "1px solid #e8e4dc", padding: "28px 24px",
                  opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(20px)",
                  transition: `all 0.5s ease ${i * 0.12}s`,
                }}
              >
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
                  <div style={{ backgroundColor: colors[i], borderRadius: 8, padding: "4px 12px" }}>
                    <span style={{ fontFamily: "var(--font-playfair)", fontSize: 22, fontWeight: 700, color: tagColors[i] }}>
                      {label}
                    </span>
                  </div>
                  <span style={{ fontSize: 18 }}>{stabilityLabel(plate.stability)}</span>
                </div>
                <h3 style={{ fontFamily: "var(--font-playfair)", fontSize: 18, fontWeight: 700, color: "#2a2a2a", marginBottom: 8, lineHeight: 1.3 }}>
                  {plate.name}
                </h3>
                <p style={{ fontFamily: "var(--font-lato)", fontSize: 13, color: "#6b6b6b", lineHeight: 1.6, marginBottom: 16 }}>
                  {plate.description}
                </p>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", borderTop: "1px solid #e8e4dc", paddingTop: 16 }}>
                  <span style={{ fontFamily: "var(--font-playfair)", fontSize: 24, fontWeight: 700, color: "#2d5a3d" }}>
                    Gs. {fmt(plate.price_gsc)}
                  </span>
                  <span style={{ fontFamily: "var(--font-lato)", fontSize: 11, color: "#6b6b6b", textTransform: "uppercase", letterSpacing: "1px" }}>
                    {plate.protein}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Extra */}
        <div
          style={{
            backgroundColor: "#fff", borderRadius: 16, border: "1px solid #e8e4dc",
            padding: "20px 28px", display: "flex", justifyContent: "space-between",
            alignItems: "center", opacity: visible ? 1 : 0, transition: "opacity 0.5s ease 0.4s",
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
            <span style={{ fontSize: 32 }}>{CURRENT_WEEK.extra.emoji}</span>
            <div>
              <div style={{ fontFamily: "var(--font-lato)", fontSize: 11, color: "#6b6b6b", textTransform: "uppercase", letterSpacing: "1px", marginBottom: 2 }}>
                Extra
              </div>
              <div style={{ fontFamily: "var(--font-playfair)", fontSize: 17, fontWeight: 700, color: "#2a2a2a" }}>
                {CURRENT_WEEK.extra.name}
              </div>
              <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "#6b6b6b" }}>
                {CURRENT_WEEK.extra.format}
              </div>
            </div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontFamily: "var(--font-playfair)", fontSize: 22, fontWeight: 700, color: "#2d5a3d" }}>
              Gs. {fmt(parseInt(CURRENT_WEEK.extra.price))}
            </div>
            <a
              href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20pedir%20${encodeURIComponent(CURRENT_WEEK.extra.name)}%20de%20esta%20semana.`}
              style={{
                display: "inline-block", marginTop: 6,
                backgroundColor: "#2d5a3d", color: "#fff",
                padding: "8px 16px", borderRadius: 8,
                fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700,
                textDecoration: "none",
              }}
            >
              Agregar →
            </a>
          </div>
        </div>

        <div style={{ textAlign: "center", marginTop: 32 }}>
          <a
            href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20pedir%20esta%20semana.%20Opciones%3A%20${CURRENT_WEEK.options.map(p => p.name).join(", ")}.`}
            style={{
              backgroundColor: "#2d5a3d", color: "#faf7f2",
              padding: "16px 40px", borderRadius: 12,
              fontFamily: "var(--font-lato)", fontSize: 16, fontWeight: 700,
              textDecoration: "none", letterSpacing: "0.3px",
              boxShadow: "0 4px 20px rgba(45, 90, 61, 0.3)",
              transition: "all 0.2s",
            }}
            onMouseEnter={(e) => {
              (e.target as HTMLElement).style.backgroundColor = "#3d7a52";
              (e.target as HTMLElement).style.transform = "translateY(-2px)";
            }}
            onMouseLeave={(e) => {
              (e.target as HTMLElement).style.backgroundColor = "#2d5a3d";
              (e.target as HTMLElement).style.transform = "translateY(0)";
            }}
          >
            Pedir esta semana →
          </a>
        </div>

        <style>{`
          @media (max-width: 900px) { .menu-grid { grid-template-columns: 1fr !important; } }
        `}</style>
      </div>
    </section>
  );
}

function Planes() {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
