          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#c4703b", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
            Planes semanales
          </div>
          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#2a2a2a", lineHeight: 1.15 }}>
            Elegí según tu hogar
          </h2>
          <p style={{ fontFamily: "var(--font-lato)", fontSize: 16, color: "#6b6b6b", marginTop: 8 }}>
            Todo incluye: 3 opciones de menú por semana, sellado al vacío, entrega domingo AM.
          </p>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 24 }} className="planes-grid">
          {PLANS.map((plan, i) => (
            <div
              key={plan.id}
              style={{
                backgroundColor: "#faf7f2", borderRadius: 20, border: "1px solid #e8e4dc",
                padding: "32px 28px",
                boxShadow: plan.populares ? "0 8px 40px rgba(196,112,59,0.15)" : "0 2px 16px rgba(0,0,0,0.04)",
                position: "relative",
                opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(30px)",
                transition: `all 0.6s ease ${i * 0.12}s`,
              }}
            >
              {plan.populares && (
                <div style={{ position: "absolute", top: -14, left: "50%", transform: "translateX(-50%)", backgroundColor: "#c4703b", color: "#fff", padding: "4px 20px", borderRadius: 999, fontFamily: "var(--font-lato)", fontSize: 11, fontWeight: 700, letterSpacing: "1px", whiteSpace: "nowrap" }}>
                  ⭐ MÁS ELEGIDO
                </div>
              )}

              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 20 }}>
                <h3 style={{ fontFamily: "var(--font-playfair)", fontSize: 26, fontWeight: 700, color: "#2a2a2a" }}>
                  {plan.name}
                </h3>
                <div style={{ backgroundColor: plan.populares ? "#fde8c8" : "#e8f0e9", borderRadius: 8, padding: "4px 10px" }}>
                  <span style={{ fontFamily: "var(--font-lato)", fontSize: 11, color: plan.populares ? "#c4703b" : "#2d5a3d", fontWeight: 700 }}>
                    {plan.tag}
                  </span>
                </div>
              </div>

              <div style={{ marginBottom: 20 }}>
                <span style={{ fontFamily: "var(--font-playfair)", fontSize: 40, fontWeight: 700, color: "#2d5a3d" }}>
                  {plan.price}
                </span>
                <span style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "#6b6b6b", marginLeft: 4 }}>
                  {plan.periodo}
                </span>
              </div>

              <p style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "#6b6b6b", lineHeight: 1.6, marginBottom: 24, minHeight: 48 }}>
                {plan.description}
              </p>

              <div style={{ borderTop: "1px solid #e8e4dc", paddingTop: 20, marginBottom: 24 }}>
                {plan.includes.map((item) => (
                  <div key={item} style={{ display: "flex", alignItems: "flex-start", gap: 10, marginBottom: 10 }}>
                    <span style={{ color: "#2d5a3d", fontSize: 16, marginTop: 1 }}>✓</span>
                    <span style={{ fontFamily: "var(--font-lato)", fontSize: 13, color: "#2a2a2a", lineHeight: 1.5 }}>
                      {item}
                    </span>
                  </div>
                ))}
              </div>

              <a
                href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Me%20interesa%20el%20plan%20${encodeURIComponent(plan.name)}.`}
                style={{
                  display: "block", textAlign: "center",
                  backgroundColor: plan.populares ? "#c4703b" : "#2d5a3d",
                  color: "#fff", padding: "14px 24px", borderRadius: 10,
                  fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 700,
                  textDecoration: "none", letterSpacing: "0.3px",
                  transition: "all 0.2s",
                }}
                onMouseEnter={(e) => { (e.target as HTMLElement).style.opacity = "0.85"; }}
                onMouseLeave={(e) => { (e.target as HTMLElement).style.opacity = "1"; }}
              >
                Elegir {plan.name} →
              </a>
            </div>
          ))}
        </div>

        <style>{`
          @media (max-width: 900px) { .planes-grid { grid-template-columns: 1fr !important; max-width: 420px; margin: 0 auto; } }
        `}</style>
      </div>
    </section>
  );
}

function ChefSection() {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => e.isIntersecting && setVisible(true), { threshold: 0.2 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  return (
    <section id="chef" ref={ref} style={{ padding: "100px 24px", backgroundColor: "#2d5a3d" }}>
      <div style={{ maxWidth: 900, margin: "0 auto", display: "grid", gridTemplateColumns: "1fr 1fr", gap: 60, alignItems: "center" }} className="chef-grid">
        <div style={{ opacity: visible ? 1 : 0, transform: visible ? "translateX(0)" : "translateX(-24px)", transition: "all 0.6s ease" }}>
          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "rgba(250,247,242,0.6)", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
            Tu chef
          </div>
          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#faf7f2", lineHeight: 1.15, marginBottom: 16 }}>
            {CHEF.name}
          </h2>
          <p style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "rgba(250,247,242,0.6)", letterSpacing: "0.5px", marginBottom: 20 }}>
            {CHEF.title}
          </p>
          <p style={{ fontFamily: "var(--font-lato)", fontSize: 16, color: "rgba(250,247,242,0.85)", lineHeight: 1.7, marginBottom: 24 }}>
            {CHEF.bio}
          </p>
          <blockquote style={{ borderLeft: "3px solid rgba(250,247,242,0.3)", paddingLeft: 20 }}>
            <p style={{ fontFamily: "var(--font-playfair)", fontSize: 18, color: "#faf7f2", fontStyle: "italic", lineHeight: 1.6 }}>
              {CHEF.philosophy}
            </p>
          </blockquote>
        </div>

        <div style={{ opacity: visible ? 1 : 0, transform: visible ? "translateX(0)" : "translateX(24px)", transition: "all 0.6s ease 0.15s" }}>
          <div style={{ backgroundColor: "rgba(255,255,255,0.1)", borderRadius: 20, padding: "32px 28px", border: "1px solid rgba(255,255,255,0.15)" }}>
            <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "rgba(250,247,242,0.5)", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 16 }}>
              Catálogo de platos
            </div>
            {[
              { cat: "Carnes y braseados", count: 9 },
              { cat: "Ave y pollo", count: 7 },
              { cat: "Sopas y legumbres", count: 9 },
            ].map((item) => (
              <div key={item.cat} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 0", borderBottom: "1px solid rgba(255,255,255,0.08)" }}>
                <span style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "rgba(250,247,242,0.8)" }}>{item.cat}</span>
                <span style={{ fontFamily: "var(--font-playfair)", fontSize: 18, fontWeight: 700, color: "#faf7f2" }}>{item.count} platos</span>
              </div>
            ))}
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px 0 0" }}>
              <span style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "rgba(250,247,242,0.8)", fontWeight: 700 }}>Total catálogo</span>
              <span style={{ fontFamily: "var(--font-playfair)", fontSize: 22, fontWeight: 700, color: "#faf7f2" }}>25 platos</span>
            </div>
          </div>
          <div style={{ marginTop: 20, display: "flex", gap: 12, flexWrap: "wrap" }}>
            {["🧊 30 días freezer", "🔥 Caldo propio", "🥬 Whole-animal", "❄️ Sin conservantes"].map((badge) => (
              <div key={badge} style={{ backgroundColor: "rgba(255,255,255,0.1)", borderRadius: 999, padding: "6px 14px" }}>
                <span style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "#faf7f2" }}>{badge}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <style>{`
        @media (max-width: 900px) { .chef-grid { grid-template-columns: 1fr !important; } }
      `}</style>
    </section>
  );
}

function FAQ() {
  const [openIdx, setOpenIdx] = useState<number | null>(0);

  return (
    <section id="faq" style={{ padding: "100px 24px", backgroundColor: "#faf7f2" }}>
      <div style={{ maxWidth: 760, margin: "0 auto" }}>
        <div style={{ textAlign: "center", marginBottom: 56 }}>
          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#c4703b", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
            Resolvé tus dudas
          </div>
          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#2a2a2a", lineHeight: 1.15 }}>
            Preguntas frecuentes
          </h2>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {FAQS.map((faq, i) => (
            <div key={i} style={{ backgroundColor: "#fff", borderRadius: 16, border: "1px solid #e8e4dc", overflow: "hidden" }}>
              <button
                onClick={() => setOpenIdx(openIdx === i ? null : i)}
                style={{
                  width: "100%", padding: "20px 24px", display: "flex",
                  justifyContent: "space-between", alignItems: "center",
                  background: "none", border: "none", cursor: "pointer", textAlign: "left",
                }}
              >
                <span style={{ fontFamily: "var(--font-lato)", fontSize: 15, fontWeight: 700, color: "#2a2a2a", paddingRight: 16 }}>
                  {faq.pregunta}
                </span>
                <span style={{ fontSize: 20, color: "#2d5a3d", transition: "transform 0.3s", transform: openIdx === i ? "rotate(45deg)" : "rotate(0deg)", flexShrink: 0 }}>
                  +
                </span>
              </button>
              {openIdx === i && (
                <div style={{ padding: "0 24px 20px", fontFamily: "var(--font-lato)", fontSize: 14, color: "#6b6b6b", lineHeight: 1.7, borderTop: "1px solid #e8e4dc", paddingTop: 16 }}>
                  {faq.respuesta}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

function Contacto() {
  return (
    <section id="contacto" style={{ padding: "100px 24px", backgroundColor: "#2d5a3d" }}>
      <div style={{ maxWidth: 760, margin: "0 auto", textAlign: "center" }}>
