        <div style={{ display: "inline-flex", flexDirection: "column", gap: 16, backgroundColor: "rgba(255,255,255,0.1)", borderRadius: 20, padding: "32px 48px", border: "1px solid rgba(255,255,255,0.15)", marginBottom: 32 }}>
          {[
