          ))}
        </div>

        <a
          href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20empezar%20con%20Prep.%20¿Podemos%20coordinar%3F`}
          style={{
            display: "inline-flex", alignItems: "center", gap: 12,
