{"content":"import { NextRequest, NextResponse } from "next/server";
import { readFileSync, writeFileSync } from "fs";
import { join } from "path";

const CATALOG_PATH = join(process.cwd(), "content", "menu-content.json");

function readContent() {
  return JSON.parse(readFileSync(CATALOG_PATH, "utf-8"));
}

function writeContent(data: unknown) {
  writeFileSync(CATALOG_PATH, JSON.stringify(data, null, 2), "utf-8");
}

// GET — return full catalog
export async function GET() {
  try {
    const data = readContent();
    return NextResponse.json({ catalog: data.catalog, extras: data.extras, site: data.site });
  } catch {
    return NextResponse.json({ error: "Failed to read content" }, { status: 500 });
  }
}

// PUT — replace catalog or update a single plate
export async function PUT(req: NextRequest) {
  try {
    const body = await req.json();
    const data = readContent();

    if (body.plates) {
      data.catalog = body.plates;
    }
    if (body.extras) {
      data.extras = body.extras;
    }
    if (body.site) {
      data.site = { ...data.site, ...body.site };
    }

    writeContent(data);
    return NextResponse.json({ ok: true, catalog: data.catalog });
  } catch {
    return NextResponse.json({ error: "Failed to write content" }, { status: 500 });
  }
}

// PATCH — update a single plate by id
export async function PATCH(req: NextRequest) {
  try {
    const { id, ...updates } = await req.json();
    const data = readContent();
    const idx = data.catalog.findIndex((p: { id: string }) => p.id === id);
    if (idx === -1) return NextResponse.json({ error: "Plate not found" }, { status: 404 });

    data.catalog[idx] = { ...data.catalog[idx], ...updates };
    writeContent(data);
    return NextResponse.json({ ok: true, plate: data.catalog[idx] });
  } catch {
    return NextResponse.json({ error: "Failed to patch plate" }, { status: 500 });
  }
}","path":"/root/sites/meal-prep-website/app/api/menu/catalog/route.ts"}

