{"content": ""use client";
import { useState, useEffect, useCallback } from "react";

// ─── TYPES ───────────────────────────────────────────────────────────────────

interface Plate {
  id: string;
  name: string;
  description: string;
  price_gsc: number;
  protein: string;
  category: string;
  stability: number;
  tags: string[];
}

interface Extra {
  id: string;
  name: string;
  price: string;
  format: string;
  emoji: string;
  type: string;
}

interface ActiveWeek {
  label: string;
  options: string[];
  extra: string;
  last_updated: string;
}

// ─── STYLES ──────────────────────────────────────────────────────────────────

const S = {
  wrap: { minHeight: "100vh", backgroundColor: "#f4f1eb", fontFamily: "var(--font-lato)" },
  header: { backgroundColor: "#2d5a3d", padding: "0 32px", height: 60, display: "flex", alignItems: "center", justifyContent: "space-between" },
  logo: { display: "flex", alignItems: "center", gap: 10 },
  tag: { fontFamily: "var(--font-playfair)", fontSize: 18, fontWeight: 700, color: "#faf7f2" },
  badge: { backgroundColor: "rgba(255,255,255,0.15)", borderRadius: 8, padding: "4px 12px", fontFamily: "var(--font-lato)", fontSize: 12, color: "#faf7f2" },
  logout: { backgroundColor: "transparent", border: "1px solid rgba(255,255,255,0.3)", borderRadius: 8, padding: "6px 16px", color: "#faf7f2", fontFamily: "var(--font-lato)", fontSize: 13, cursor: "pointer" as const },
  container: { maxWidth: 1200, margin: "0 auto", padding: "32px 24px" },
  sectionLabel: { fontFamily: "var(--font-lato)", fontSize: 11, fontWeight: 700, color: "#6b6b6b", letterSpacing: "2px", textTransform: "uppercase" as const, marginBottom: 16 },
  row: { display: "grid", gridTemplateColumns: "1fr 320px", gap: 32 } as React.CSSProperties,
  card: { backgroundColor: "#fff", borderRadius: 16, border: "1px solid #e8e4dc", padding: "20px 24px", marginBottom: 12, transition: "box-shadow 0.2s" },
  cardHover: { boxShadow: "0 4px 20px rgba(0,0,0,0.08)" },
  plateName: { fontFamily: "var(--font-playfair)", fontSize: 18, fontWeight: 700, color: "#2a2a2a", marginBottom: 4 },
  plateDesc: { fontFamily: "var(--font-lato)", fontSize: 13, color: "#6b6b6b", lineHeight: 1.5, marginBottom: 12 },
  plateMeta: { display: "flex", gap: 8, flexWrap: "wrap" as const },
  tag2: { backgroundColor: "#e8f0e9", borderRadius: 6, padding: "3px 10px", fontFamily: "var(--font-lato)", fontSize: 11, color: "#2d5a3d", fontWeight: 700 },
  btn: { padding: "8px 16px", borderRadius: 8, border: "none", fontFamily: "var(--font-lato)", fontSize: 13, fontWeight: 700, cursor: "pointer" as const, transition: "opacity 0.2s" },
  btnPrimary: { backgroundColor: "#2d5a3d", color: "#fff" },
  btnDanger: { backgroundColor: "#dc2626", color: "#fff" },
  btnOutline: { backgroundColor: "transparent", border: "1px solid #e8e4dc", color: "#2a2a2a" },
  input: { width: "100%", padding: "8px 12px", borderRadius: 8, border: "1px solid #e8e4dc", fontFamily: "var(--font-lato)", fontSize: 14, boxSizing: "border-box" as const },
  label: { fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#2a2a2a", display: "block", marginBottom: 4 },
  row2: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 } as React.CSSProperties,
  saveBar: { position: "fixed", bottom: 0, left: 0, right: 0, backgroundColor: "#2d5a3d", padding: "16px 32px", display: "flex", justifyContent: "space-between", alignItems: "center", boxShadow: "0 -4px 20px rgba(0,0,0,0.15)" },
  select: { width: "100%", padding: "8px 12px", borderRadius: 8, border: "1px solid #e8e4dc", fontFamily: "var(--font-lato)", fontSize: 14, boxSizing: "border-box" as const, backgroundColor: "#fff" },
  slot: { backgroundColor: "#fff", borderRadius: 12, border: "2px solid #e8e4dc", padding: "16px", marginBottom: 12 },
  slotLabel: { fontFamily: "var(--font-playfair)", fontSize: 14, fontWeight: 700, color: "#2d5a3d", marginBottom: 8 },
  extraSlot: { backgroundColor: "#fde8c8", borderRadius: 12, border: "2px solid #c4703b", padding: "16px" },
  tabBtn: (active: boolean) => ({ padding: "8px 20px", borderRadius: 8, border: "none", fontFamily: "var(--font-lato)", fontSize: 13, fontWeight: 700, cursor: "pointer" as const, backgroundColor: active ? "#2d5a3d" : "#e8e4dc", color: active ? "#fff" : "#6b6b6b" }),
};

// ─── HELPERS ─────────────────────────────────────────────────────────────────

const fmtGsc = (n: number) => `Gs. ${n.toLocaleString("es-PY")}`;
const STABILITY_ICONS = ["🧊", "🧊🧊", "🧊🧊🧊"];
const PROTEIN_COLORS: Record<string, string> = {
  carne: "#fde8c8",
  pollo: "#d4edda",
  vegetariano: "#fff3cd",
  legumbre: "#e8f0e9",
};
const SLOT_LABELS = ["Opción A", "Opción B", "Opción C"];

// ─── COMPONENT ────────────────────────────────────────────────────────────────

export default function AdminMenuPage() {
  const [catalog, setCatalog] = useState<Plate[]>([]);
  const [extras, setExtras] = useState<Extra[]>([]);
  const [activeWeek, setActiveWeek] = useState<ActiveWeek>({ label: "", options: ["", "", ""], extra: "", last_updated: "" });
  const [tab, setTab] = useState<"week" | "catalog">("week");
  const [editingPlate, setEditingPlate] = useState<Plate | null>(null);
  const [saving, setSaving] = useState(false);
  const [dirty, setDirty] = useState(false);
  const [msg, setMsg] = useState<{ type: "ok" | "err"; text: string } | null>(null);
  const [filter, setFilter] = useState("");
  const [hoveredCard, setHoveredCard] = useState<string | null>(null);

  const load = useCallback(async () => {
    const [catRes, weekRes] = await Promise.all([
      fetch("/api/menu/catalog"),
      fetch("/api/menu/week"),
    ]);
    const catData = await catRes.json();
    const weekData = await weekRes.json();
    setCatalog(catData.catalog || []);
    setExtras(catData.extras || []);
    setActiveWeek(weekData);
  }, []);

  useEffect(() => { load(); }, [load]);

  const notify = (type: "ok" | "err", text: string) => {
    setMsg({ type, text });
    setTimeout(() => setMsg(null), 3000);
  };

  // Week editing
  const setSlot = (i: number, id: string) => {
    setActiveWeek((w) => {
      const opts = [...w.options];
      opts[i] = id;
      return { ...w, options: opts };
    });
    setDirty(true);
  };

  const setExtraSlot = (id: string) => {
    setActiveWeek((w) => ({ ...w, extra: id }));
    setDirty(true);
  };

  const saveWeek = async () => {
    setSaving(true);
    try {
      const res = await fetch("/api/menu/week", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(activeWeek),
      });
      if (res.ok) { notify("ok", "Menú semanal guardado ✓"); setDirty(false); }
      else notify("err", "Error al guardar");
    } finally { setSaving(false); }
  };

  // Plate editing
  const openEdit = (p: Plate) => setEditingPlate({ ...p });
  const cancelEdit = () => setEditingPlate(null);

  const saveEdit = async () => {
    if (!editingPlate) return;
    setSaving(true);
    try {
      const res = await fetch("/api/menu/catalog", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(editingPlate),
      });
      if (res.ok) {
        setCatalog((c) => c.map((p) => p.id === editingPlate.id ? editingPlate : p));
        setEditingPlate(null);
        notify("ok", "Plato guardado ✓");
      } else { notify("err", "Error al guardar"); }
    } finally { setSaving(false); }
  };

  const logout = () => {
    document.cookie = "admin_token=; path=/; max-age=0";
    window.location.href = "/admin/login";
  };

  const filteredCatalog = catalog.filter(
    (p) => p.name.toLowerCase().includes(filter.toLowerCase()) || p.category.toLowerCase().includes(filter.toLowerCase())
  );

  const slotPlate = (id: string) => catalog.find((p) => p.id === id);

  return (
    <div style={S.wrap}>
      {/* Header */}
      <header style={S.header}>
        <div style={S.logo}>
          <span style={S.tag}>🍲 Prep</span>
          <span style={S.badge}>Panel Admin</span>
        </div>
        <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
          <span style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "rgba(250,247,242,0.6)" }}>
            Último cambio: {activeWeek.last_updated || "—"}
          </span>
          <button style={S.logout} onClick={logout}>Cerrar sesión</button>
        </div>
      </header>

      {/* Toast */}
      {msg && (
        <div style={{
          position: "fixed", top: 80, right: 24, zIndex: 100,
          backgroundColor: msg.type === "ok" ? "#dcfce7" : "#fee2e2",
          color: msg.type === "ok" ? "#166534" : "#dc2626",
          padding: "12px 20px", borderRadius: 12,
          fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 700,
          boxShadow: "0 4px 20px rgba(0,0,0,0.12)",
        }}>
          {msg.text}
        </div>
      )}

      <div style={S.container}>
        {/* Tab switcher */}
        <div style={{ display: "flex", gap: 8, marginBottom: 28 }}>
          <button style={S.tabBtn(tab === "week")} onClick={() => setTab("week")}>Semana activa</button>
          <button style={S.tabBtn(tab === "catalog")} onClick={() => setTab("catalog")}>Catálogo de platos</button>
        </div>

        {tab === "week" && (
          <div style={S.row2}>
            {/* Left: slot picker */}
            <div>
              <p style={S.sectionLabel}>Menú de esta semana</p>
              <div style={{ marginBottom: 20 }}>
                <label style={S.label}>Label de la semana</label>
                <input
                  value={activeWeek.label}
                  onChange={(e) => { setActiveWeek((w) => ({ ...w, label: e.target.value })); setDirty(true); }}
                  style={S.input}
                  placeholder="Semana del 13 al 18 mayo"
                />
              </div>

              {SLOT_LABELS.map((lbl, i) => {
                const plate = slotPlate(activeWeek.options[i]);
                return (
                  <div key={i} style={S.slot}>
                    <div style={S.slotLabel}>{lbl}</div>
                    <select value={activeWeek.options[i]} onChange={(e) => setSlot(i, e.target.value)} style={S.select}>
                      <option value="">— Sin asignar —</option>
                      {catalog.map((p) => (
                        <option key={p.id} value={p.id}>{p.name} ({fmtGsc(p.price_gsc)})</option>
                      ))}
                    </select>
                    {plate && (
                      <div style={{ marginTop: 10, padding: "10px 14px", backgroundColor: "#faf7f2", borderRadius: 10 }}>
                        <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "#6b6b6b" }}>{plate.description}</div>
                        <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "#2d5a3d", fontWeight: 700, marginTop: 4 }}>
                          {fmtGsc(plate.price_gsc)} · {plate.protein} · {STABILITY_ICONS[plate.stability - 1]}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}

              {/* Extra */}
              <div style={S.extraSlot}>
                <div style={{ ...S.slotLabel, color: "#c4703b" }}>Extra de la semana</div>
                <select value={activeWeek.extra} onChange={(e) => setExtraSlot(e.target.value)} style={S.select}>
                  <option value="">— Ninguno —</option>
                  {extras.map((e) => (
                    <option key={e.id} value={e.id}>{e.emoji} {e.name} ({e.price})</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Right: preview */}
            <div>
              <p style={S.sectionLabel}>Vista previa pública</p>
              <div style={{ backgroundColor: "#fff", borderRadius: 16, padding: 20, border: "1px solid #e8e4dc", position: "sticky", top: 20 }}>
                <div style={{ backgroundColor: "#2d5a3d", borderRadius: 10, padding: "10px 16px", marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <span style={{ fontFamily: "var(--font-lato)", fontSize: 11, color: "#faf7f2", fontWeight: 700, letterSpacing: "1px" }}>
                    TU FREEZER — {(activeWeek.label || "SEMANA").toUpperCase()}
                  </span>
                  <span>✅</span>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                  {activeWeek.options.map((id, i) => {
                    const p = slotPlate(id);
                    const bg = ["#e8f0e9", "#fde8c8", "#d4edda"][i];
                    if (!p) return <div key={i} style={{ backgroundColor: bg, borderRadius: 10, padding: 14, textAlign: "center", opacity: 0.4, fontFamily: "var(--font-lato)", fontSize: 11, color: "#6b6b6b" }}>Sin asignar</div>;
                    return (
                      <div key={p.id} style={{ backgroundColor: bg, borderRadius: 10, padding: "14px 12px", textAlign: "center" }}>
                        <div style={{ fontFamily: "var(--font-lato)", fontSize: 11, fontWeight: 700, color: "#2a2a2a", lineHeight: 1.3 }}>
                          {p.name.length > 28 ? p.name.substring(0, 26) + "…" : p.name}
                        </div>
                        <div style={{ fontFamily: "var(--font-lato)", fontSize: 10, color: "#6b6b6b", marginTop: 2 }}>{fmtGsc(p.price_gsc)}</div>
                      </div>
                    );
                  })}
                </div>
                {activeWeek.extra && (() => {
                  const ex = extras.find((e) => e.id === activeWeek.extra);
                  return ex ? (
                    <div style={{ marginTop: 10, backgroundColor: "#fde8c8", borderRadius: 10, padding: "12px 14px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                      <div><span style={{ fontSize: 18, marginRight: 8 }}>{ex.emoji}</span><span style={{ fontFamily: "var(--font-lato)", fontSize: 13, fontWeight: 700, color: "#2a2a2a" }}>{ex.name}</span></div>
                      <span style={{ fontFamily: "var(--font-playfair)", fontSize: 16, fontWeight: 700, color: "#2d5a3d" }}>{ex.price}</span>
                    </div>
                  ) : null;
                })()}
                <div style={{ marginTop: 16, display: "flex", gap: 8 }}>
                  <a href="/" target="_blank" style={{ flex: 1, textAlign: "center", backgroundColor: "#e8f0e9", borderRadius: 8, padding: "10px", fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#2d5a3d", textDecoration: "none" }}>
                    Ver site →
                  </a>
                </div>
              </div>
            </div>
          </div>
        )}

        {tab === "catalog" && (
          <div>
            <p style={S.sectionLabel}>Catálogo ({catalog.length} platos)</p>
            <div style={{ marginBottom: 16 }}>
              <input
                value={filter}
                onChange={(e) => setFilter(e.target.value)}
                placeholder="Buscar por nombre o categoría…"
                style={{ ...S.input, maxWidth: 400 }}
              />
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 12 }}>
              {filteredCatalog.map((plate) => (
                <div
                  key={plate.id}
                  style={{
                    ...S.card,
                    ...(hoveredCard === plate.id ? S.cardHover : {}),
                  }}
                  onMouseEnter={() => setHoveredCard(plate.id)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
                    <div>
                      <h3 style={S.plateName}>{plate.name}</h3>
                      <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "#6b6b6b" }}>{plate.id}</div>
                    </div>
                    <span style={{ fontSize: 18 }}>{STABILITY_ICONS[plate.stability - 1]}</span>
                  </div>
                  <p style={S.plateDesc}>{plate.description}</p>
                  <div style={S.plateMeta}>
                    <span style={{ ...S.tag2, backgroundColor: PROTEIN_COLORS[plate.protein] || "#e8f0e9" }}>{plate.protein}</span>
                    <span style={S.tag2}>{plate.category}</span>
                    <span style={{ ...S.tag2, color: "#2d5a3d", fontWeight: 700 }}>{fmtGsc(plate.price_gsc)}</span>
                    {plate.tags.map((t) => <span key={t} style={S.tag2}>{t}</span>)}
                  </div>
                  <div style={{ marginTop: 14, display: "flex", gap: 8 }}>
                    <button
                      style={{ ...S.btn, ...S.btnPrimary }}
                      onClick={() => openEdit(plate)}
                    >
                      Editar
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Save bar */}
      {dirty && (
        <div style={S.saveBar}>
          <span style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "#faf7f2", fontWeight: 700 }}>
            Hay cambios sin guardar
          </span>
          <div style={{ display: "flex", gap: 12 }}>
            <button
              onClick={() => { setDirty(false); setActiveWeek({ label: "", options: ["", "", ""], extra: "", last_updated: "" }); load(); }}
              style={{ ...S.btn, backgroundColor: "rgba(255,255,255,0.15)", color: "#faf7f2", border: "1px solid rgba(255,255,255,0.3)" }}
            >
              Descartar
            </button>
            <button
              onClick={saveWeek}
              disabled={saving}
              style={{ ...S.btn, ...S.btnPrimary, opacity: saving ? 0.6 : 1 }}
            >
              {saving ? "Guardando…" : "Guardar cambios ✓"}
            </button>
          </div>
        </div>
      )}

      {/* Edit modal */}
      {editingPlate && (
        <div style={{ position: "fixed", inset: 0, backgroundColor: "rgba(0,0,0,0.5)", zIndex: 200, display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
          <div style={{ backgroundColor: "#fff", borderRadius: 20, padding: "32px", width: "100%", maxWidth: 520, maxHeight: "90vh", overflowY: "auto" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24 }}>
              <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: 22, fontWeight: 700, color: "#2a2a2a" }}>Editar plato</h2>
              <button onClick={cancelEdit} style={{ background: "none", border: "none", fontSize: 22, cursor: "pointer", color: "#6b6b6b" }}>✕</button>
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              {[
                { label: "Nombre", key: "name" as const, type: "text" },
                { label: "Precio (Gs)", key: "price_gsc" as const, type: "number" },
                { label: "ID", key: "id" as const, type: "text" },
              ].map(({ label, key, type }) => (
                <div key={key}>
                  <label style={S.label}>{label}</label>
                  <input
                    type={type}
                    value={editingPlate[key]}
                    onChange={(e) => setEditingPlate((p) => p ? { ...p, [key]: type === "number" ? parseInt(e.target.value) || 0 : e.target.value } : p)}
                    style={S.input}
                  />
                </div>
              ))}
              <div>
                <label style={S.label}>Descripción</label>
                <textarea
                  value={editingPlate.description}
                  onChange={(e) => setEditingPlate((p) => p ? { ...p, description: e.target.value } : p)}
                  rows={3}
                  style={{ ...S.input, resize: "vertical" as const }}
                />
              </div>
              <div style={S.row2}>
                <div>
                  <label style={S.label}>Proteína</label>
                  <select
                    value={editingPlate.protein}
                    onChange={(e) => setEditingPlate((p) => p ? { ...p, protein: e.target.value } : p)}
                    style={S.select}
                  >
                    <option value="carne">carne</option>
                    <option value="pollo">pollo</option>
                    <option value="vegetariano">vegetariano</option>
                    <option value="legumbre">legumbre</option>
                  </select>
                </div>
                <div>
                  <label style={S.label}>Estabilidad</label>
                  <select
                    value={editingPlate.stability}
                    onChange={(e) => setEditingPlate((p) => p ? { ...p, stability: parseInt(e.target.value) } : p)}
                    style={S.select}
                  >
                    {[1, 2, 3].map((n) => <option key={n} value={n}>{STABILITY_ICONS[n - 1]} {n === 1 ? "Baja" : n === 2 ? "Media" : "Alta"}</option>)}
                  </select>
                </div>
              </div>
            </div>
            <div style={{ display: "flex", gap: 12, marginTop: 24, justifyContent: "flex-end" }}>
              <button onClick={cancelEdit} style={{ ...S.btn, ...S.btnOutline }}>Cancelar</button>
              <button onClick={saveEdit} disabled={saving} style={{ ...S.btn, ...S.btnPrimary, opacity: saving ? 0.6 : 1 }}>
                {saving ? "Guardando…" : "Guardar ✓"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
